import React from 'react';
const MissionList = () => {
    return (
        <div className="flex flex-col gap-4">
            <div className="bg-white shadow-md rounded-lg p-4">
                <h3 className="text-lg font-semibold">Nhiệm vụ 1</h3>
                <p className="text-gray-600">Mô tả nhiệm vụ 1</p>
            </div>
            <div className="bg-white shadow-md rounded-lg p-4">
                <h3 className="text-lg font-semibold">Nhiệm vụ 2</h3>
                <p className="text-gray-600">Mô tả nhiệm vụ 2</p>
            </div>
        </div>
    );
};
export default MissionList;
